from flask import Flask, request, jsonify
import logging
import re

app = Flask(__name__)

# Configure logging
logging.basicConfig(filename='application.log', level=logging.INFO, format='%(asctime)s - %(message)s')

# Function to sanitize log input
def sanitize_input(input_string):
    return re.sub(r'[^\w\s@.-]', '', input_string)

@app.route('/login', methods=['POST'])
def login():
    username = request.form.get('username', '')
    password = request.form.get('password', '')
    email = request.form.get('email', '')
    ip_address = request.remote_addr
    user_agent = request.headers.get('User-Agent', '')

    # Sanitize inputs before logging
    sanitized_username = sanitize_input(username)
    sanitized_email = sanitize_input(email)
    sanitized_user_agent = sanitize_input(user_agent)

    # Log the login attempt
    logging.info(f"Login attempt - Username: {sanitized_username}, Email: {sanitized_email}, IP: {ip_address}, User-Agent: {sanitized_user_agent}")

    # Dummy authentication logic
    if username == "admin" and password == "password":
        return jsonify({"message": "Login successful"}), 200
    else:
        return jsonify({"message": "Invalid credentials"}), 401

if __name__ == '__main__':
    app.run(debug=True)